export function findNeighbors(pathName: string): {
	previous: SidebarNavItem | null;
	next: SidebarNavItem | null;
} {
	const path = pathName.split("?")[0].split("#")[0];
	const index = fullNavItems.findIndex((item) => item.href === path);

	let previous: SidebarNavItem | null = null;
	for (let i = index - 1; i >= 0; i--) {
		if (fullNavItems[i].href !== "/llms.txt") {
			previous = fullNavItems[i];
			break;
		}
	}

	let next: SidebarNavItem | null = null;
	for (let i = index + 1; i < fullNavItems.length; i++) {
		if (fullNavItems[i].href !== "/llms.txt") {
			next = fullNavItems[i];
			break;
		}
	}

	return { previous, next };
}

function transformClassText(
	text: string,
	menuColor: string,
	isTranslucent: boolean
): { newText: string } {
	let newText = text;

	if (menuColor === "inverted" || menuColor === "inverted-translucent") {
		newText = newText.replace(/cn-menu-target/g, "dark");
	} else {
		newText = newText.replace(/cn-menu-target/g, "");
	}

	if (isTranslucent) {
		const merged = twMerge(newText, TRANSLUCENT_CLASSES);
		newText = merged.replace(/\s*\bcn-menu-translucent\b\s*/g, " ").trim();
	} else {
		newText = newText.replace(/cn-menu-translucent/g, "");
	}

	newText = newText.replace(/\s{2,}/g, " ").replace(/^\s+|\s+$/g, "");
	return { newText };
}

export function getLineOffsets(text: string) {
    const lineOffsets = [];
    let isLineStart = true;

    for (let i = 0; i < text.length; i++) {
        if (isLineStart) {
            lineOffsets.push(i);
            isLineStart = false;
        }
        const ch = text.charAt(i);
        isLineStart = ch === '\r' || ch === '\n';
        if (ch === '\r' && i + 1 < text.length && text.charAt(i + 1) === '\n') {
            i++;
        }
    }

    if (isLineStart && text.length > 0) {
        lineOffsets.push(text.length);
    }

    return lineOffsets;
}

export function getLatestOpeningTag(
    svelteDoc: SvelteDocument,
    offset: number
): SvelteLogicTag | null {
    // Only use content up to the position and strip out html comments
    const content = svelteDoc
        .getText()
        .substring(0, offset)
        .replace(/<!--(.*?)-->/g, '');
    const lastIdxs = [
        idxOfLastOpeningTag(content, 'each'),
        idxOfLastOpeningTag(content, 'if'),
        idxOfLastOpeningTag(content, 'await'),
        idxOfLastOpeningTag(content, 'key'),
        idxOfLastOpeningTag(content, 'snippet')
    ];
    const lastIdx = lastIdxs.sort((i1, i2) => i2.lastIdx - i1.lastIdx);
    return lastIdx[0].lastIdx === -1 ? null : lastIdx[0].tag;
}

