export function replaceDeep<T extends Record<string, any>>(
    obj: T,
    searchStr: string | RegExp,
    replacementStr: string
): T {
    return _replaceDeep(obj);

    function _replaceDeep(_obj: any): any {
        if (typeof _obj === 'string') {
            return _obj.replace(searchStr, replacementStr);
        }
        if (Array.isArray(_obj)) {
            return _obj.map((entry) => _replaceDeep(entry));
        }
        if (typeof _obj === 'object') {
            return Object.keys(_obj).reduce((_o, key) => {
                _o[key] = _replaceDeep(_obj[key]);
                return _o;
            }, {} as any);
        }
        return _obj;
    }
}

function get_code_frame(line, column) {
	const lines = state.source_lines;
	const frame_start = Math.max(0, line - 2);
	const frame_end = Math.min(line + 3, lines.length);
	const digits = String(frame_end + 1).length;
	return lines
		.slice(frame_start, frame_end)
		.map((str, i) => {
			const is_error_line = frame_start + i === line;
			const line_num = String(i + frame_start + 1).padStart(digits, ' ');
			if (is_error_line) {
				const indicator =
					' '.repeat(digits + 2 + tabs_to_spaces(str.slice(0, column)).length) + '^';
				return `${line_num}: ${tabs_to_spaces(str)}\n${indicator}`;
			}
			return `${line_num}: ${tabs_to_spaces(str)}`;
		})
		.join('\n');
}

function activate(el, set_bubble_pos = true) {
	if (options.customStyles && el !== active_el) {
		if (active_el) {
			active_el.classList.remove('svelte-inspector-active-target');
		}
		if (el) {
			el.classList.add('svelte-inspector-active-target');
		}
	}
	if (el) {
		const { file, line, column } = el.__svelte_meta.loc;
		file_loc = `${file}:${line + 1}:${column + 1}`;
	} else {
		file_loc = null;
	}
	active_el = el;
	if (set_bubble_pos) {
		const pos = el.getBoundingClientRect();
		x = Math.ceil(pos.left);
		y = Math.ceil(pos.bottom - 20);
	}
}

