() => {
  if (active) {
    const handleKeydown = (e: KeyboardEvent) => {
      switch (e.key) {
        case "Escape":
          skip();
          break;
        case "ArrowRight":
        case "ArrowDown":
          e.preventDefault();
          next();
          break;
        case "ArrowLeft":
        case "ArrowUp":
          e.preventDefault();
          if (!isFirstStep) previous();
          break;
      }
    };

    window.addEventListener("keydown", handleKeydown);
    return () => window.removeEventListener("keydown", handleKeydown);
  }
}

export function useCurrentBreakpoint(): () => "xs" | "sm" | "md" | "lg" | "xl" | "2xl" {
  let currentBreakpoint = $state<"xs" | "sm" | "md" | "lg" | "xl" | "2xl">("xs");

  $effect(() => {
    if (typeof window === "undefined") return;

    const updateBreakpoint = (): void => {
      const width = window.innerWidth;
      if (width >= 1536) currentBreakpoint = "2xl";
      else if (width >= 1280) currentBreakpoint = "xl";
      else if (width >= 1024) currentBreakpoint = "lg";
      else if (width >= 768) currentBreakpoint = "md";
      else if (width >= 640) currentBreakpoint = "sm";
      else currentBreakpoint = "xs";
    };

    updateBreakpoint();
    window.addEventListener("resize", updateBreakpoint);

    return (): void => {
      window.removeEventListener("resize", updateBreakpoint);
    };
  });

  return (): "xs" | "sm" | "md" | "lg" | "xl" | "2xl" => currentBreakpoint;
}

function find_sections(node: HTMLElement) {
  // find closes previous section anchor
  const section = [...node.ownerDocument.querySelectorAll("#mainContent > :where(h2, h3) > [id]")]
    .map((x: Element) => ({ id: x.id, top: x.parentElement?.offsetTop ?? Infinity, obj: x }))
    .filter((x) => x.top < (node?.offsetTop ?? Infinity))
    .filter((x) => x.id)
    .slice(-1)
    .shift();
  // console.log('section:', section);
  if (section) {
    const pathname = new URL(node.baseURI).pathname;
    path = new URL(pathname.slice(1) + ".md", gitHub);
    path.hash = section.id.replaceAll("_", "-").replaceAll("/", "").toLowerCase();
  }
}

